import { Result, err, ok } from 'neverthrow';
import { ScrapeRequest, ScrapeResponse } from '../../../firecrawl-compat/src';
import { CrawlEngine, CrawlFailure } from '../engine';

export class FirecrawlCloudEngine implements CrawlEngine {
  readonly name = 'firecrawl-cloud';
  readonly priority = 80;

  supports(_input: ScrapeRequest): boolean {
    return true;
  }

  async scrape(input: ScrapeRequest): Promise<Result<ScrapeResponse, CrawlFailure>> {
    const apiKey = process.env.FIRECRAWL_CLOUD_API_KEY;

    if (!apiKey) {
      return err({
        code: 'BLOCKED',
        message: 'Firecrawl Cloud API key not configured',
        engineName: this.name,
      });
    }

    try {
      // Basic fetch call to simulated Firecrawl Cloud API
      const response = await fetch('https://api.firecrawl.dev/v1/scrape', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`,
        },
        body: JSON.stringify(input),
      });

      if (!response.ok) {
        return err({
          code: 'UPSTREAM_DOWN',
          message: `Firecrawl Cloud returned ${response.status}: ${response.statusText}`,
          engineName: this.name,
        });
      }

      const data = await response.json() as ScrapeResponse;
      return ok(data);
    } catch (e) {
      return err({
        code: 'UNKNOWN',
        message: e instanceof Error ? e.message : 'Unknown error during Firecrawl Cloud fetch',
        engineName: this.name,
      });
    }
  }
}
